import React, { useState, useEffect, useRef } from 'react';
import { MessageSquare, Send, X, Sparkles, User, Bot } from 'lucide-react';
import { GoogleGenAI } from '@google/genai';

const AIAssistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{ role: 'user' | 'assistant'; text: string }[]>([
    { role: 'assistant', text: 'Olá, noivinha! Eu sou a sua consultora virtual da Ellegance Noivas. Como posso ajudar você a encontrar o vestido dos seus sonhos hoje?' }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSendMessage = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setInput('');
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages.map(m => ({
          role: m.role === 'user' ? 'user' : 'model',
          parts: [{ text: m.text }]
        })), { role: 'user', parts: [{ text: userMessage }] }],
        config: {
          systemInstruction: 'Você é a Estilista Virtual da Ellegance Noivas, localizada em Praia Grande, SP (Av. Pres. Kennedy, 3321). Seu tom é extremamente elegante, acolhedor, romântico e profissional. Ajude noivas a entenderem estilos de vestidos (Princesa, Sereia, Minimalista, Boho, Clássico) e destaque que a Ellegance oferece atendimento personalizado e exclusivo. Se perguntarem sobre agendamento, direcione para o WhatsApp (13) 99691-6451. Não use Markdown complexo, prefira textos fluidos e gentis.',
          temperature: 0.7,
        },
      });

      const aiText = response.text || "Desculpe, tive um pequeno problema. Poderia repetir?";
      setMessages(prev => [...prev, { role: 'assistant', text: aiText }]);
    } catch (error) {
      console.error('Gemini Error:', error);
      setMessages(prev => [...prev, { role: 'assistant', text: "No momento estou ocupada atendendo outra noiva, mas você pode nos chamar no WhatsApp para um atendimento imediato! 💍" }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <>
      {/* Trigger Button */}
      <button
        onClick={() => setIsOpen(true)}
        className="fixed bottom-24 right-6 z-50 p-4 bg-brand-gold text-white rounded-full shadow-2xl hover:scale-110 active:scale-95 transition-all duration-300"
        title="Consultora Virtual"
      >
        <Sparkles size={24} />
      </button>

      {/* Chat Window */}
      <div className={`fixed bottom-6 right-6 z-[60] w-[90vw] md:w-[400px] h-[600px] max-h-[80vh] bg-white rounded-2xl shadow-2xl flex flex-col overflow-hidden transition-all duration-500 origin-bottom-right ${isOpen ? 'scale-100 opacity-100' : 'scale-0 opacity-0 pointer-events-none'}`}>
        {/* Header */}
        <div className="bg-brand-offwhite border-b border-brand-rose/30 p-6 flex justify-between items-center">
          <div className="flex items-center space-x-3">
            <div className="p-2 bg-brand-rose/20 rounded-full">
              <Sparkles size={20} className="text-brand-gold" />
            </div>
            <div>
              <h3 className="font-serif text-lg text-stone-800">Estilista Virtual</h3>
              <p className="text-[10px] uppercase tracking-widest text-brand-gold font-bold">Ellegance Noivas</p>
            </div>
          </div>
          <button onClick={() => setIsOpen(false)} className="text-stone-400 hover:text-stone-800 transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Messages */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 scroll-smooth">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed ${msg.role === 'user' ? 'bg-brand-rose text-stone-800 rounded-tr-none' : 'bg-brand-offwhite text-stone-700 rounded-tl-none'}`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start italic text-stone-400 text-xs animate-pulse">
              Desenhando sua resposta...
            </div>
          )}
        </div>

        {/* Input */}
        <div className="p-4 bg-white border-t border-stone-100">
          <div className="relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Pergunte sobre estilos ou sobre a loja..."
              className="w-full pl-4 pr-12 py-3 bg-stone-50 border border-stone-100 rounded-full text-sm focus:outline-none focus:border-brand-gold transition-all"
            />
            <button
              onClick={handleSendMessage}
              disabled={isLoading}
              className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-brand-gold text-white rounded-full disabled:opacity-50"
            >
              <Send size={16} />
            </button>
          </div>
        </div>
      </div>
    </>
  );
};

export default AIAssistant;

