import React, { useState, useMemo } from 'react';
import { ChevronRight, MessageCircle, SlidersHorizontal } from 'lucide-react';

// Tipos de dados para o catálogo
type DressType = 'Clássico' | 'Moderno' | 'Princesa' | 'Minimalista' | 'Sereia' | 'Boho';
type DressColor = 'Branco' | 'Off-White' | 'Nude' | 'Champagne';
type DressSize = '36' | '38' | '40' | '42' | '44' | '46' | '48';

interface Dress {
  id: number;
  name: string;
  type: DressType;
  color: DressColor;
  size: DressSize;
  image: string;
}

const Gallery: React.FC = () => {
  const [selectedType, setSelectedType] = useState<DressType | 'Todos'>('Todos');
  const [selectedColor, setSelectedColor] = useState<DressColor | 'Todas'>('Todas');
  const [selectedSize, setSelectedSize] = useState<DressSize | 'Todos'>('Todos');

  // Dados Mockados (Serão substituídos pelas suas fotos)
  const dresses: Dress[] = [
    { id: 1, name: 'Modelo Aurora', type: 'Princesa', color: 'Branco', size: '38', image: 'https://images.unsplash.com/photo-1594462285124-d33d9efec3d2?q=80&w=600' },
    { id: 2, name: 'Modelo Celine', type: 'Minimalista', color: 'Off-White', size: '40', image: 'https://images.unsplash.com/photo-1510076857177-74700760beaa?q=80&w=600' },
    { id: 3, name: 'Modelo Diana', type: 'Sereia', color: 'Nude', size: '42', image: 'https://images.unsplash.com/photo-1519741497674-611481863552?q=80&w=600' },
    { id: 4, name: 'Modelo Ester', type: 'Clássico', color: 'Branco', size: '36', image: 'https://images.unsplash.com/photo-1549419051-11ec3285e6BC?q=80&w=600' },
    { id: 5, name: 'Modelo Flora', type: 'Boho', color: 'Champagne', size: '44', image: 'https://images.unsplash.com/photo-1541250848049-b4f7141dca3f?q=80&w=600' },
    { id: 6, name: 'Modelo Gisele', type: 'Moderno', color: 'Off-White', size: '38', image: 'https://images.unsplash.com/photo-1520854221256-17451cc331bf?q=80&w=600' },
    { id: 7, name: 'Modelo Helena', type: 'Princesa', color: 'Branco', size: '40', image: 'https://images.unsplash.com/photo-1519225421980-715cb0215aed?q=80&w=600' },
    { id: 8, name: 'Modelo Íris', type: 'Minimalista', color: 'Off-White', size: '42', image: 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?q=80&w=600' },
  ];

  const filteredDresses = useMemo(() => {
    return dresses.filter(dress => {
      const typeMatch = selectedType === 'Todos' || dress.type === selectedType;
      const colorMatch = selectedColor === 'Todas' || dress.color === selectedColor;
      const sizeMatch = selectedSize === 'Todos' || dress.size === selectedSize;
      return typeMatch && colorMatch && sizeMatch;
    });
  }, [selectedType, selectedColor, selectedSize]);

  const FilterSection = ({ label, options, current, setter }: { label: string, options: string[], current: string, setter: (val: any) => void }) => (
    <div className="mb-8">
      <h4 className="text-[10px] uppercase tracking-[0.3em] text-stone-400 font-bold mb-4">{label}</h4>
      <div className="flex flex-wrap gap-2">
        {options.map(opt => (
          <button
            key={opt}
            onClick={() => setter(opt)}
            className={`px-5 py-2 text-[11px] uppercase tracking-widest font-semibold rounded-full border transition-all ${
              current === opt 
              ? 'bg-brand-gold border-brand-gold text-white shadow-md' 
              : 'bg-white border-stone-100 text-stone-500 hover:border-brand-rose'
            }`}
          >
            {opt}
          </button>
        ))}
      </div>
    </div>
  );

  return (
    <div className="max-w-7xl mx-auto px-6 lg:px-12">
      <div className="flex flex-col lg:flex-row lg:items-end justify-between mb-16 gap-8">
        <div>
          <h2 className="text-stone-400 text-xs font-bold uppercase tracking-[0.4em] mb-4">Catálogo Exclusivo</h2>
          <h3 className="text-4xl md:text-6xl font-serif text-stone-900 leading-tight">
            Encontre o seu <span className="italic text-brand-rose">estilo</span>
          </h3>
        </div>
        <p className="max-w-md text-stone-500 text-sm leading-relaxed mb-1">
          Utilize os filtros abaixo para selecionar o tipo, a cor e o tamanho ideal para o seu grande dia.
        </p>
      </div>

      {/* Seção de Filtros */}
      <div className="bg-white border border-stone-100 p-8 lg:p-12 mb-16 shadow-sm rounded-sm">
        <div className="flex items-center space-x-3 mb-10 text-brand-gold">
          <SlidersHorizontal size={20} />
          <span className="uppercase tracking-[0.3em] text-xs font-bold">Personalizar Busca</span>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
          <FilterSection 
            label="Tipo de Vestido" 
            options={['Todos', 'Clássico', 'Moderno', 'Princesa', 'Minimalista', 'Sereia', 'Boho']} 
            current={selectedType} 
            setter={setSelectedType} 
          />
          <FilterSection 
            label="Cor Desejada" 
            options={['Todas', 'Branco', 'Off-White', 'Nude', 'Champagne']} 
            current={selectedColor} 
            setter={setSelectedColor} 
          />
          <FilterSection 
            label="Tamanho" 
            options={['Todos', '36', '38', '40', '42', '44', '46', '48']} 
            current={selectedSize} 
            setter={setSelectedSize} 
          />
        </div>

        {(selectedType !== 'Todos' || selectedColor !== 'Todas' || selectedSize !== 'Todos') && (
          <button 
            onClick={() => { setSelectedType('Todos'); setSelectedColor('Todas'); setSelectedSize('Todos'); }}
            className="mt-4 text-[10px] uppercase tracking-widest text-stone-400 hover:text-brand-gold transition-colors font-bold underline underline-offset-4"
          >
            Limpar todos os filtros
          </button>
        )}
      </div>

      {/* Grid de Resultados */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
        {filteredDresses.length > 0 ? (
          filteredDresses.map((dress) => (
            <div key={dress.id} className="group flex flex-col h-full bg-white border border-stone-50 overflow-hidden hover:shadow-2xl transition-all duration-500">
              <div className="relative aspect-[3/4] overflow-hidden">
                <img
                  src={dress.image}
                  alt={dress.name}
                  className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110"
                />
                <div className="absolute top-4 right-4 bg-white/90 backdrop-blur-sm px-3 py-1 text-[9px] uppercase tracking-widest font-bold text-stone-800 rounded-full shadow-sm">
                  Tam {dress.size}
                </div>
              </div>
              <div className="p-6 flex flex-col flex-1">
                <div className="flex justify-between items-start mb-2">
                  <h4 className="font-serif text-xl text-stone-900">{dress.name}</h4>
                  <span className="text-[9px] uppercase tracking-widest text-brand-gold font-bold">{dress.type}</span>
                </div>
                <p className="text-stone-400 text-[10px] uppercase tracking-[0.2em] mb-6">Cor: {dress.color}</p>

                <a
                  href={`https://wa.me/5513996916451?text=Olá! Me interessei pelo ${dress.name} (${dress.type}), na cor ${dress.color} e tamanho ${dress.size}. Está disponível para visita?`}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="mt-auto flex items-center justify-center space-x-2 w-full py-4 bg-stone-900 text-white text-[10px] uppercase tracking-[0.2em] font-bold hover:bg-brand-gold transition-all group-hover:bg-brand-gold"
                >
                  <MessageCircle size={14} />
                  <span>Tenho Interesse</span>
                </a>
              </div>
            </div>
          ))
        ) : (
          <div className="col-span-full py-20 text-center bg-stone-50 rounded-sm">
            <h4 className="font-serif text-2xl text-stone-400 mb-4">Nenhum modelo encontrado</h4>
            <p className="text-stone-500 text-sm">Tente ajustar seus filtros ou entre em contato para pedidos personalizados.</p>
          </div>
        )}
      </div>

      <div className="mt-24 pt-16 border-t border-stone-100 text-center">
        <p className="text-stone-400 text-xs uppercase tracking-[0.3em] mb-8">Não encontrou o que procurava?</p>
        <a 
          href="https://wa.me/5513996916451" 
          className="inline-flex items-center space-x-3 text-brand-gold hover:text-brand-goldSoft transition-colors border-b border-brand-gold/30 pb-2"
        >
          <span className="text-xs uppercase tracking-[0.4em] font-bold">Consulte nossa curadoria completa</span>
          <ChevronRight size={16} />
        </a>
      </div>
    </div>
  );
};

export default Gallery;

