  ];

  const filteredDresses = useMemo(() => {
    return dresses.filter(dress => {
      const typeMatch = selectedType === 'Todos' || dress.type === selectedType;
      const colorMatch = selectedColor === 'Todas' || dress.color === selectedColor;
      const sizeMatch = selectedSize === 'Todos' || dress.size === selectedSize;
      return typeMatch && colorMatch && sizeMatch;
