          <div className="h-px bg-stone-200 my-8"></div>

          <FilterSection 
            label="3. Tamanho" 
            options={['Todos', '36', '38', '40', '42', '44', '46', '48']} 
            current={selectedSize} 
            setter={setSelectedSize} 
            icon={<CheckCircle2 size={14} className={selectedSize !== 'Todos' ? 'text-brand-gold' : 'text-stone-300'} />}
