export type ViewType = 'home' | 'catalog';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewType>('home');

  const [catalogItems, setCatalogItems] = useState<CatalogItem[]>([]);

  const navigateTo = (view: ViewType, sectionId?: string) => {
    if (view !== currentView) {
      setCurrentView(view);
    }

    if (sectionId) {
      setTimeout(() => {
        const element = document.getElementById(sectionId);
        if (element) {
          element.scrollIntoView({ behavior: 'smooth' });
        } else {
          window.scrollTo({ top: 0, behavior: 'smooth' });
        }
      }, 150);
    } else {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleAddItem = (newItem: Omit<CatalogItem, 'id'>) => {
    const itemWithId = {
      ...newItem,
      id: Date.now(),
      isNew: true,
      isVisible: true,
      isAvailable: true,
      tag: newItem.tag || 'Novo Modelo'
    };
    setCatalogItems(prev => [itemWithId, ...prev]);
  };

  const handleToggleVisibility = (id: number) => {
    setCatalogItems(prev => prev.map(item => 
      item.id === id ? { ...item, isVisible: !item.isVisible } : item
    ));
  };

  const handleToggleAvailability = (id: number) => {
    setCatalogItems(prev => prev.map(item => 
      item.id === id ? { ...item, isAvailable: !item.isAvailable } : item
    ));
  };

  const handleDeleteItem = (id: number) => {
    if (window.confirm("Tem certeza que deseja excluir este modelo definitivamente?")) {
      setCatalogItems(prev => prev.filter(item => item.id !== id));
    }
  };

  return (
    <div className="min-h-screen font-sans text-stone-800 bg-white selection:bg-brand-rose selection:text-stone-900 overflow-x-hidden">
      <Navbar currentView={currentView} onNavigate={navigateTo} />

      <main className="transition-opacity duration-500 min-h-screen">
        {currentView === 'home' ? (
          <div className="animate-fade-in">
            <section id="inicio" className="scroll-mt-0">
              <Hero onNavigate={navigateTo} />
            </section>

            <section id="sobre" className="py-20 lg:py-32 bg-brand-offwhite overflow-hidden scroll-mt-24">
              <About />
            </section>

            <section id="diferenciais" className="py-20 lg:py-32 bg-brand-offwhite scroll-mt-24">
              <Differentiators />
            </section>

            <section id="avaliacoes" className="py-20 lg:py-32 scroll-mt-24">
              <Testimonials />
            </section>

            <section id="contato" className="py-20 lg:py-32 bg-stone-50 scroll-mt-24">
              <Contact />
            </section>
          </div>
        ) : (
          <div className="pt-24 lg:pt-40 pb-20 lg:pb-32 bg-white animate-fade-in min-h-screen">
            <Gallery 
              items={catalogItems} 
              onBack={() => navigateTo('home')} 
              onAddItem={handleAddItem}
              onToggleVisibility={handleToggleVisibility}
              onToggleAvailability={handleToggleAvailability}
              onDeleteItem={handleDeleteItem}
            />
          </div>
        )}
      </main>

      <Footer onNavigate={navigateTo} />
      <WhatsAppButton />
      <AIAssistant onAddItem={handleAddItem} />
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  ChevronRight, 
  MessageCircle, 
  ArrowLeft, 
  User, 
  Users, 
  Sparkles, 
  PlusCircle, 
  Settings, 
  Eye, 
  EyeOff, 
  Slash, 
  CheckCircle, 
  X, 
  Maximize2,
  Lock,
  Trash2
} from 'lucide-react';
import AdminPanel from './AdminPanel';

export type Gender = 'Feminino' | 'Masculino';
export type CatalogCategory = 'Vestido de Noiva' | 'Vestido de Festa' | 'Traje do Noivo' | 'Terno Social';

export interface CatalogItem {
  id: number;
  name: string;
  gender: Gender;
  category: CatalogCategory;
  color: string;
  image: string;
  isNew?: boolean;
  isVisible: boolean;
  isAvailable: boolean;
  tag?: string;
}

interface GalleryProps {
  items: CatalogItem[];
  onBack?: () => void;
  onAddItem: (item: Omit<CatalogItem, 'id'>) => void;
  onToggleVisibility: (id: number) => void;
  onToggleAvailability: (id: number) => void;
  onDeleteItem: (id: number) => void;
}

const Gallery: React.FC<GalleryProps> = ({ 
  items, 
  onBack, 
  onAddItem, 
  onToggleVisibility, 
  onToggleAvailability,
  onDeleteItem
}) => {
  const [selectedGender, setSelectedGender] = useState<Gender>('Feminino');
  const [selectedCategory, setSelectedCategory] = useState<CatalogCategory | 'Todas'>('Todas');
  const [showAdmin, setShowAdmin] = useState(false);
  const [managementMode, setManagementMode] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [showPasswordPrompt, setShowPasswordPrompt] = useState<{ type: 'add' | 'manage' } | null>(null);
  const [passwordInput, setPasswordInput] = useState('');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  const categories: Record<Gender, CatalogCategory[]> = {
    'Feminino': ['Vestido de Noiva', 'Vestido de Festa'],
    'Masculino': ['Traje do Noivo', 'Terno Social']
  };

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const genderMatch = item.gender === selectedGender;
      const categoryMatch = selectedCategory === 'Todas' || item.category === selectedCategory;
      // No modo gerenciamento, mostra tudo. Fora dele, apenas os visíveis.
      const visibilityMatch = managementMode ? true : item.isVisible;
      return genderMatch && categoryMatch && visibilityMatch;
    });
  }, [items, selectedGender, selectedCategory, managementMode]);

  const handleAdminAction = (type: 'add' | 'manage') => {
    if (isAdminAuthenticated) {
      if (type === 'add') setShowAdmin(true);
      if (type === 'manage') setManagementMode(!managementMode);
    } else {
      setShowPasswordPrompt({ type });
    }
  };

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Senha padrão definida como "ellegance2025" conforme sugerido para sistemas de admin
    if (passwordInput === 'ellegance2025') {
      setIsAdminAuthenticated(true);
      const type = showPasswordPrompt?.type;
      setShowPasswordPrompt(null);
      setPasswordInput('');
      if (type === 'add') setShowAdmin(true);
      if (type === 'manage') setManagementMode(true);
    } else {
      alert("Senha incorreta");
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-6 lg:px-12 animate-fade-in relative">
      {/* Lightbox / Visualização Ampliada */}
      {selectedImage && (
        <div 
          className="fixed inset-0 z-[200] bg-stone-900/95 flex items-center justify-center p-4 md:p-12 animate-fade-in"
          onClick={() => setSelectedImage(null)}
        >
          <button className="absolute top-6 right-6 text-white hover:text-brand-gold transition-colors">
            <X size={32} />
          </button>
          <img 
            src={selectedImage} 
            alt="Vestido Ampliado" 
            className="max-w-full max-h-full object-contain shadow-2xl rounded-sm"
          />
        </div>
      )}

      {/* Prompt de Senha */}
      {showPasswordPrompt && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center p-4 bg-stone-900/60 backdrop-blur-sm">
          <div className="bg-white p-8 rounded-sm shadow-2xl w-full max-w-sm border-t-4 border-brand-gold">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-serif text-xl text-stone-900">Acesso Restrito</h3>
              <button onClick={() => setShowPasswordPrompt(null)}><X size={20}/></button>
            </div>
            <p className="text-[10px] uppercase tracking-widest text-stone-400 mb-6">Insira a senha de gestão da Ellegance</p>
            <form onSubmit={handlePasswordSubmit} className="space-y-4">
              <input 
                type="password" 
                autoFocus
                value={passwordInput}
                onChange={(e) => setPasswordInput(e.target.value)}
                placeholder="Senha de acesso"
                className="w-full p-3 border-b border-stone-100 focus:border-brand-gold outline-none text-sm"
              />
              <button className="w-full py-3 bg-stone-900 text-white text-[10px] uppercase tracking-widest font-bold hover:bg-brand-gold transition-all">
                Confirmar Acesso
              </button>
            </form>
          </div>
        </div>
      )}

      {showAdmin && (
        <AdminPanel 
          onClose={() => setShowAdmin(false)} 
          onAddItem={onAddItem} 
        />
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between mb-12 space-y-6 md:space-y-0">
        {onBack && (
          <button 
            onClick={onBack}
            className="group flex items-center space-x-2 text-stone-400 hover:text-brand-gold transition-colors"
          >
            <ArrowLeft size={18} className="group-hover:-translate-x-1 transition-transform" />
            <span className="text-[10px] uppercase tracking-[0.3em] font-bold">Voltar para Início</span>
          </button>
        )}

        <div className="flex items-center space-x-4">
          <button 
            onClick={() => handleAdminAction('manage')}
            className={`inline-flex items-center space-x-3 px-6 py-3 border transition-all rounded-sm text-[10px] uppercase tracking-[0.2em] font-bold shadow-sm ${
              managementMode ? 'bg-stone-900 border-stone-900 text-white' : 'bg-white border-stone-200 text-stone-600 hover:border-brand-gold hover:text-brand-gold'
            }`}
          >
            <Settings size={16} />
            <span>{managementMode ? 'Sair da Gestão' : 'Gerenciar Vitrine'}</span>
          </button>

          <button 
            onClick={() => handleAdminAction('add')}
            className="inline-flex items-center space-x-3 px-6 py-3 bg-brand-offwhite border border-brand-rose text-brand-gold hover:bg-brand-rose hover:text-stone-800 transition-all rounded-sm text-[10px] uppercase tracking-[0.2em] font-bold shadow-sm"
          >
            <PlusCircle size={16} />
            <span>Adicionar Novo</span>
          </button>
        </div>
      </div>

      <div className="text-center mb-16">
        <h2 className="text-brand-gold text-xs font-bold uppercase tracking-[0.6em] mb-6">Coleções Ellegance</h2>
        <h3 className="text-4xl md:text-6xl font-serif text-stone-900 mb-8 leading-tight">
