import React, { useState, useRef } from 'react';
import { X, Upload, Plus, Sparkles, Check } from 'lucide-react';
import { CatalogItem, Gender, CatalogCategory } from './Gallery';

interface AdminPanelProps {
  onAddItem: (item: Omit<CatalogItem, 'id'>) => void;
  onClose: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onAddItem, onClose }) => {
  const [name, setName] = useState('');
  const [color, setColor] = useState('');
  const [gender, setGender] = useState<Gender>('Feminino');
  const [category, setCategory] = useState<CatalogCategory>('Vestido de Festa');
  const [image, setImage] = useState<string | null>(null);
  const [isSuccess, setIsSuccess] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !color || !image) return;

    onAddItem({
      name,
      color,
      gender,
      category,
      image,
      isVisible: true,
      isAvailable: true,
      isNew: true,
      tag: 'Lançamento Manual'
    });

    setIsSuccess(true);
    setTimeout(() => {
      onClose();
    }, 1500);
  };

  return (
    <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-stone-900/60 backdrop-blur-sm animate-fade-in">
      <div className="bg-white w-full max-w-2xl rounded-sm shadow-2xl overflow-hidden flex flex-col md:flex-row max-h-[90vh]">
        {/* Lado Esquerdo: Preview da Imagem */}
        <div className="w-full md:w-1/2 bg-brand-offwhite border-b md:border-b-0 md:border-r border-stone-100 flex flex-col items-center justify-center p-8">
          {image ? (
            <div className="relative w-full aspect-[3/4] rounded-sm overflow-hidden shadow-lg border-2 border-brand-rose">
              <img src={image} alt="Preview" className="w-full h-full object-cover" />
              <button 
                onClick={() => setImage(null)}
                className="absolute top-2 right-2 p-2 bg-white/80 rounded-full text-stone-800 hover:bg-white"
              >
                <X size={16} />
              </button>
            </div>
          ) : (
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="w-full aspect-[3/4] border-2 border-dashed border-stone-200 rounded-sm flex flex-col items-center justify-center space-y-4 hover:border-brand-gold hover:bg-white transition-all group"
            >
              <div className="p-4 bg-white rounded-full text-stone-300 group-hover:text-brand-gold shadow-sm">
                <Upload size={32} />
              </div>
              <div className="text-center">
                <p className="text-[10px] uppercase tracking-widest font-bold text-stone-400">Carregar Foto</p>
                <p className="text-[8px] text-stone-300 mt-1 uppercase">Clique para selecionar</p>
              </div>
            </button>
          )}
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleImageChange} 
            accept="image/*" 
            className="hidden" 
          />
        </div>

        {/* Lado Direito: Formulário */}
        <div className="w-full md:w-1/2 p-8 flex flex-col relative">
          <button 
            onClick={onClose}
            className="absolute top-4 right-4 text-stone-300 hover:text-stone-800 transition-colors"
          >
            <X size={20} />
          </button>

          <div className="mb-8">
            <h3 className="font-serif text-2xl text-stone-900 mb-2">Cadastrar Modelo</h3>
            <p className="text-[9px] uppercase tracking-[0.3em] text-brand-gold font-bold">Gestão Ellegance Noivas</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6 overflow-y-auto pr-2">
            <div>
              <label className="block text-[10px] uppercase tracking-widest font-bold text-stone-400 mb-2">Nome do Modelo</label>
              <input 
                type="text" 
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="Ex: Vestido Sereia com Renda"
                className="w-full p-3 border-b border-stone-100 focus:border-brand-gold outline-none text-sm transition-colors"
                required
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] uppercase tracking-widest font-bold text-stone-400 mb-2">Linha</label>
                <select 
                  value={gender}
                  onChange={(e) => {
                    const val = e.target.value as Gender;
                    setGender(val);
                    setCategory(val === 'Feminino' ? 'Vestido de Festa' : 'Traje do Noivo');
                  }}
                  className="w-full p-3 border-b border-stone-100 focus:border-brand-gold outline-none text-sm bg-transparent"
                >
                  <option value="Feminino">Feminina</option>
                  <option value="Masculino">Masculina</option>
                </select>
              </div>
              <div>
                <label className="block text-[10px] uppercase tracking-widest font-bold text-stone-400 mb-2">Tipo de Roupa</label>
                <select 
                  value={category}
                  onChange={(e) => setCategory(e.target.value as CatalogCategory)}
                  className="w-full p-3 border-b border-stone-100 focus:border-brand-gold outline-none text-sm bg-transparent"
                >
                  {gender === 'Feminino' ? (
                    <>
                      <option value="Vestido de Noiva">Vestido de Noiva</option>
                      <option value="Vestido de Festa">Vestido de Festa</option>
                    </>
                  ) : (
                    <>
                      <option value="Traje do Noivo">Traje do Noivo</option>
                      <option value="Terno Social">Terno Social</option>
                    </>
                  )}
                </select>
              </div>
            </div>

            <div>
              <label className="block text-[10px] uppercase tracking-widest font-bold text-stone-400 mb-2">Cor Predominante</label>
              <input 
                type="text" 
                value={color}
                onChange={(e) => setColor(e.target.value)}
                placeholder="Ex: Rosé, Off-White, Marsala"
                className="w-full p-3 border-b border-stone-100 focus:border-brand-gold outline-none text-sm"
                required
              />
            </div>

            <button
              type="submit"
              disabled={isSuccess || !image}
              className={`w-full py-4 flex items-center justify-center space-x-3 text-[10px] uppercase tracking-widest font-bold transition-all ${
                isSuccess 
                ? 'bg-green-500 text-white' 
                : 'bg-stone-900 text-white hover:bg-brand-gold shadow-lg active:scale-95 disabled:opacity-50'
              }`}
            >
              {isSuccess ? (
                <>
                  <Check size={16} />
                  <span>Adicionado com Sucesso!</span>
                </>
              ) : (
                <>
                  <Plus size={16} />
                  <span>Adicionar à Vitrine</span>
                </>
              )}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default AdminPanel;

