import AdminPanel from './AdminPanel';

export type Gender = 'Feminino' | 'Masculino';
export type CatalogCategory = 'Vestido de Noiva' | 'Vestido de Festa' | 'Traje do Noivo' | 'Terno Social';

export interface CatalogItem {
  id: number;
  name: string;
  gender: Gender;
  category: CatalogCategory;
  color: string;
  image: string;
  isNew?: boolean;
  isVisible: boolean;
  isAvailable: boolean;
  tag?: string;
}

interface GalleryProps {
  items: CatalogItem[];
  onBack?: () => void;
  onAddItem: (item: Omit<CatalogItem, 'id'>) => void;
  onToggleVisibility: (id: number) => void;
  onToggleAvailability: (id: number) => void;
  onDeleteItem: (id: number) => void;
}

const Gallery: React.FC<GalleryProps> = ({ 
  items, 
  onBack, 
  onAddItem, 
  onToggleVisibility, 
  onToggleAvailability,
  onDeleteItem
}) => {
  const [selectedGender, setSelectedGender] = useState<Gender>('Feminino');
  const [selectedCategory, setSelectedCategory] = useState<CatalogCategory | 'Todas'>('Todas');
  const [showAdmin, setShowAdmin] = useState(false);
  const [managementMode, setManagementMode] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [showPasswordPrompt, setShowPasswordPrompt] = useState<{ type: 'add' | 'manage' } | null>(null);
  const [passwordInput, setPasswordInput] = useState('');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  const categories: Record<Gender, CatalogCategory[]> = {
    'Feminino': ['Vestido de Noiva', 'Vestido de Festa'],
    'Masculino': ['Traje do Noivo', 'Terno Social']
  };

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const genderMatch = item.gender === selectedGender;
      const categoryMatch = selectedCategory === 'Todas' || item.category === selectedCategory;
      const visibilityMatch = managementMode ? true : item.isVisible;
      return genderMatch && categoryMatch && visibilityMatch;
    });
  }, [items, selectedGender, selectedCategory, managementMode]);

  const handleAdminAction = (type: 'add' | 'manage') => {
    if (isAdminAuthenticated) {
      if (type === 'add') setShowAdmin(true);
      if (type === 'manage') setManagementMode(!managementMode);
    } else {
      setShowPasswordPrompt({ type });
    }
  };

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Senha atualizada para 2312 conforme solicitado
    if (passwordInput === '2312') {
      setIsAdminAuthenticated(true);
      const type = showPasswordPrompt?.type;
      setShowPasswordPrompt(null);
      setPasswordInput('');
      if (type === 'add') setShowAdmin(true);
      if (type === 'manage') setManagementMode(true);
    } else {
      alert("Senha de gerenciamento incorreta.");
      setPasswordInput('');
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-6 lg:px-12 animate-fade-in relative">
      {/* Lightbox para visualização ampliada */}
      {selectedImage && (
        <div 
          className="fixed inset-0 z-[200] bg-stone-900/95 flex items-center justify-center p-4 md:p-12 animate-fade-in cursor-zoom-out"
          onClick={() => setSelectedImage(null)}
        >
          <button className="absolute top-6 right-6 text-white hover:text-brand-gold transition-colors">
            <X size={40} />
          </button>
          <img 
            src={selectedImage} 
            alt="Detalhe do Modelo" 
            className="max-w-full max-h-full object-contain shadow-2xl rounded-sm border border-white/10"
          />
        </div>
      )}

      {/* Prompt de Senha para Gestão */}
      {showPasswordPrompt && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center p-4 bg-stone-900/60 backdrop-blur-sm">
          <div className="bg-white p-8 rounded-sm shadow-2xl w-full max-w-sm border-t-4 border-brand-gold animate-fade-in">
            <div className="flex justify-between items-center mb-6">
              <div className="flex items-center space-x-3">
                <Lock size={20} className="text-brand-gold" />
                <h3 className="font-serif text-xl text-stone-900">Área Restrita</h3>
              </div>
              <button onClick={() => setShowPasswordPrompt(null)} className="text-stone-300 hover:text-stone-600">
                <X size={20}/>
              </button>
            </div>
            <p className="text-[10px] uppercase tracking-widest text-stone-400 mb-6 font-bold">Autenticação de Gerenciamento</p>
            <form onSubmit={handlePasswordSubmit} className="space-y-4">
              <input 
                type="password" 
                autoFocus
                value={passwordInput}
                onChange={(e) => setPasswordInput(e.target.value)}
                placeholder="Insira a senha de 4 dígitos"
                className="w-full p-4 bg-stone-50 border border-stone-100 focus:border-brand-gold outline-none text-center text-lg tracking-[0.5em] font-bold"
              />
              <button className="w-full py-4 bg-stone-900 text-white text-[10px] uppercase tracking-widest font-bold hover:bg-brand-gold transition-all shadow-lg">
                Acessar Ferramentas
              </button>
            </form>
          </div>
        </div>
      )}

      {showAdmin && (
        <AdminPanel 
          onClose={() => setShowAdmin(false)} 
          onAddItem={onAddItem} 
        />
      )}

      {/* BARRA DE FERRAMENTAS DO CATÁLOGO */}
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-16 space-y-6 md:space-y-0">
        {onBack && (
          <button 
            onClick={onBack}
            className="group flex items-center space-x-3 text-stone-400 hover:text-brand-gold transition-colors"
          >
            <ArrowLeft size={18} className="group-hover:-translate-x-1 transition-transform" />
            <span className="text-[10px] uppercase tracking-[0.3em] font-bold">Voltar ao Início</span>
          </button>
        )}

        <div className="flex items-center bg-brand-offwhite p-1 rounded-sm border border-stone-100 shadow-sm">
          <button 
            onClick={() => handleAdminAction('add')}
            className="flex items-center space-x-3 px-6 py-3 bg-white border border-stone-100 text-stone-700 hover:text-brand-gold hover:border-brand-gold transition-all rounded-sm text-[10px] uppercase tracking-[0.2em] font-bold"
          >
            <PlusCircle size={16} />
            <span>Adicionar Modelo</span>
          </button>

          <div className="w-[1px] h-6 bg-stone-200 mx-1"></div>

          <button 
            onClick={() => handleAdminAction('manage')}
            className={`flex items-center space-x-3 px-6 py-3 transition-all rounded-sm text-[10px] uppercase tracking-[0.2em] font-bold ${
              managementMode 
              ? 'bg-stone-900 text-white shadow-md' 
              : 'bg-white text-stone-700 hover:text-brand-gold'
            }`}
          >
            <Settings size={16} className={managementMode ? 'animate-spin-slow' : ''} />
            <span>{managementMode ? 'Encerrar Gestão' : 'Gerenciar'}</span>
          </button>
        </div>
      </div>

      <div className="text-center mb-16">
        <h2 className="text-brand-gold text-xs font-bold uppercase tracking-[0.6em] mb-6">Coleções Ellegance</h2>
        <h3 className="text-4xl md:text-6xl font-serif text-stone-900 mb-8 leading-tight">
          Nossa <span className="italic text-brand-rose">Vitrine Digital.</span>
        </h3>
        <p className="max-w-2xl mx-auto text-stone-500 text-lg font-light leading-relaxed">
          {managementMode 
            ? 'Modo de Gestão Ativo: Use o ícone de lápis em cada foto para ocultar ou marcar como indisponível.' 
            : 'Explore nossos modelos exclusivos. Cada peça é selecionada para garantir elegância e sofisticação.'}
        </p>
      </div>

      {/* FILTROS DE LINHA E CATEGORIA */}
      <div className="flex flex-col items-center mb-20 space-y-8">
        <div className="bg-brand-offwhite p-1 rounded-sm flex border border-stone-100 shadow-sm overflow-hidden">
          <button
            onClick={() => { setSelectedGender('Feminino'); setSelectedCategory('Todas'); }}
            className={`flex items-center space-x-3 px-8 md:px-12 py-4 rounded-sm text-[10px] uppercase tracking-[0.2em] font-bold transition-all duration-500 ${
              selectedGender === 'Feminino' ? 'bg-stone-900 text-white shadow-xl' : 'text-stone-400 hover:text-brand-gold'
            }`}
          >
            <Users size={16} />
            <span>Linha Feminina</span>
          </button>
          <button
            onClick={() => { setSelectedGender('Masculino'); setSelectedCategory('Todas'); }}
            className={`flex items-center space-x-3 px-8 md:px-12 py-4 rounded-sm text-[10px] uppercase tracking-[0.2em] font-bold transition-all duration-500 ${
              selectedGender === 'Masculino' ? 'bg-stone-900 text-white shadow-xl' : 'text-stone-400 hover:text-brand-gold'
            }`}
          >
            <User size={16} />
            <span>Linha Masculina</span>
          </button>
        </div>

        <div className="flex flex-wrap justify-center gap-4">
          <button
            onClick={() => setSelectedCategory('Todas')}
            className={`px-8 py-3 text-[9px] uppercase tracking-[0.25em] font-bold rounded-sm border transition-all ${
              selectedCategory === 'Todas' ? 'bg-brand-gold border-brand-gold text-white shadow-lg' : 'bg-white border-stone-100 text-stone-400 hover:border-brand-gold hover:text-brand-gold'
            }`}
          >
            Ver Tudo
          </button>
          {categories[selectedGender].map(cat => (
            <button
              key={cat}
              onClick={() => setSelectedCategory(cat)}
              className={`px-8 py-3 text-[9px] uppercase tracking-[0.25em] font-bold rounded-sm border transition-all ${
                selectedCategory === cat ? 'bg-brand-gold border-brand-gold text-white shadow-lg' : 'bg-white border-stone-100 text-stone-400 hover:border-brand-gold hover:text-brand-gold'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {/* GRID DE PRODUTOS */}
      <div className="flex justify-center">
        {filteredItems.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-16 w-full">
            {filteredItems.map((item) => (
              <div key={item.id} className={`group flex flex-col animate-fade-in mx-auto w-full max-w-sm transition-all duration-500 ${!item.isVisible ? 'opacity-40 grayscale' : 'opacity-100'}`}>
                <div className="relative aspect-[3/4] overflow-hidden bg-stone-50 mb-8 rounded-sm shadow-sm group/card cursor-pointer">
                  <img
                    src={item.image}
                    alt={item.name}
                    className={`w-full h-full object-cover transition-transform duration-[5s] group-hover:scale-110 ${!item.isAvailable ? 'brightness-50' : ''}`}
                    onClick={() => setSelectedImage(item.image)}
                  />

                  {/* ÍCONE DE LÁPIS (GERENCIAMENTO) */}
                  {managementMode && (
                    <div className="absolute top-4 right-4 z-30 flex flex-col items-end space-y-2 group/edit">
                      <div className="p-3 bg-brand-gold text-white rounded-full shadow-xl hover:scale-110 transition-transform cursor-pointer">
                        <Pencil size={18} />
                      </div>

                      {/* Sub-menu de ações de edição */}
                      <div className="flex flex-col space-y-2 opacity-0 group-hover/edit:opacity-100 transition-opacity duration-300">
                        <button 
                          onClick={() => onToggleVisibility(item.id)}
                          className={`p-3 rounded-full shadow-lg transition-all ${item.isVisible ? 'bg-white text-stone-800' : 'bg-stone-900 text-white'}`}
                          title={item.isVisible ? 'Ocultar da Vitrine' : 'Exibir na Vitrine'}
                        >
                          {item.isVisible ? <Eye size={18} /> : <EyeOff size={18} />}
                        </button>
                        <button 
                          onClick={() => onToggleAvailability(item.id)}
                          className={`p-3 rounded-full shadow-lg transition-all ${item.isAvailable ? 'bg-white text-stone-800' : 'bg-red-500 text-white'}`}
                          title={item.isAvailable ? 'Marcar como Indisponível' : 'Marcar como Disponível'}
                        >
                          {item.isAvailable ? <Slash size={18} /> : <CheckCircle size={18} />}
                        </button>
                        <button 
                          onClick={() => onDeleteItem(item.id)}
                          className="p-3 bg-white text-red-600 rounded-full shadow-lg hover:bg-red-600 hover:text-white transition-all"
                          title="Excluir Definitivamente"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    </div>
                  )}

                  {/* Overlay de Ampliação */}
                  <div 
                    onClick={() => setSelectedImage(item.image)}
                    className="absolute inset-0 bg-stone-900/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center pointer-events-none"
                  >
                    <Maximize2 className="text-white" size={32} />
                  </div>

                  {/* Etiqueta de Indisponibilidade */}
                  {!item.isAvailable && (
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none bg-stone-900/20 backdrop-blur-[1px]">
                       <span className="bg-stone-900/90 text-white px-8 py-3 text-[10px] uppercase tracking-[0.4em] font-bold border border-white/20 shadow-2xl">
                         Indisponível
                       </span>
                    </div>
                  )}

                  {item.tag && item.isVisible && item.isAvailable && (
                    <div className="absolute top-8 left-8">
                      <div className="bg-white/95 backdrop-blur-md px-5 py-2 flex items-center space-x-2 shadow-xl border border-stone-100">
                        <Sparkles size={12} className="text-brand-gold" />
                        <span className="text-[9px] uppercase tracking-[0.4em] font-bold text-stone-800">{item.tag}</span>
                      </div>
                    </div>
                  )}
                </div>

                <div className="flex flex-col flex-1 px-2 text-center md:text-left">
                  <h4 className="font-serif text-3xl text-stone-900 group-hover:text-brand-gold transition-colors mb-4 flex items-center justify-center md:justify-start">
                    {item.name}
                    {!item.isVisible && <EyeOff size={18} className="ml-3 text-stone-300" />}
                  </h4>

                  <div className="flex items-center justify-center md:justify-start space-x-4 mb-10">
                    <span className="text-[10px] uppercase tracking-[0.3em] font-bold text-brand-gold">{item.category}</span>
                    <div className="w-1 h-1 bg-stone-200 rounded-full"></div>
                    <span className="text-[10px] uppercase tracking-[0.3em] font-medium text-stone-400">{item.color}</span>
                  </div>

                  <a
                    href={`https://wa.me/5513996916451?text=Olá! Gostaria de agendar uma prova para o modelo: ${item.name}`}
                    target="_blank"
                    rel="noopener noreferrer"
                    className={`inline-flex items-center justify-between w-full border border-stone-100 bg-stone-50 p-6 group/btn transition-all duration-500 rounded-sm ${!item.isAvailable ? 'opacity-40 cursor-not-allowed' : 'hover:bg-stone-900 hover:text-white'}`}
                    onClick={(e) => !item.isAvailable && e.preventDefault()}
                  >
                    <span className="text-[10px] uppercase tracking-[0.4em] font-bold">
                      {item.isAvailable ? 'Agendar Prova' : 'Consulte Disponibilidade'}
                    </span>
                    <MessageCircle size={20} className="text-brand-gold group-hover/btn:scale-110 transition-transform" />
                  </a>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="py-40 text-center bg-brand-offwhite rounded-sm border border-stone-100 flex flex-col items-center w-full px-12">
            <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-8 shadow-sm">
              <Sparkles size={32} className="text-stone-200" />
            </div>
            <h4 className="font-serif text-3xl text-stone-400 mb-4 italic">Acervo em atualização</h4>
            <p className="text-stone-500 text-sm max-w-sm mx-auto mb-10 font-light leading-relaxed">
              Estamos preparando novidades incríveis para você. Fale com nossas consultoras para ver as peças recém-chegadas.
            </p>
            <a 
              href="https://wa.me/5513996916451"
              className="px-12 py-5 bg-stone-900 text-white text-[11px] uppercase tracking-widest font-bold hover:bg-brand-gold transition-all shadow-xl"
            >
              Chamar no WhatsApp
            </a>
          </div>
        )}
      </div>

      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes spin-slow {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        .animate-spin-slow {
          animation: spin-slow 8s linear infinite;
        }
      `}} />
    </div>
  );
};

export default Gallery;

import React, { useState, useMemo } from 'react';
import { 
  MessageCircle, 
  ArrowLeft, 
  User, 
  Users, 
  Sparkles, 
  PlusCircle, 
  Settings, 
  Eye, 
  EyeOff, 
  Slash, 
  CheckCircle, 
  X, 
  Maximize2,
  Lock,
  Trash2,
  Pencil
} from 'lucide-react';
import AdminPanel from './AdminPanel';

export type Gender = 'Feminino' | 'Masculino';
export type CatalogCategory = 'Vestido de Noiva' | 'Vestido de Festa' | 'Traje do Noivo' | 'Terno Social';

export interface CatalogItem {
  id: number;
  name: string;
  gender: Gender;
  category: CatalogCategory;
  color: string;
  image: string;
  isNew?: boolean;
  isVisible: boolean;
  isAvailable: boolean;
  tag?: string;
}

interface GalleryProps {
  items: CatalogItem[];
  onBack?: () => void;
  onAddItem: (item: Omit<CatalogItem, 'id'>) => void;
  onToggleVisibility: (id: number) => void;
  onToggleAvailability: (id: number) => void;
  onDeleteItem: (id: number) => void;
}

const Gallery: React.FC<GalleryProps> = ({ 
  items, 
  onBack, 
  onAddItem, 
  onToggleVisibility, 
  onToggleAvailability,
  onDeleteItem
}) => {
  const [selectedGender, setSelectedGender] = useState<Gender>('Feminino');
  const [selectedCategory, setSelectedCategory] = useState<CatalogCategory | 'Todas'>('Todas');
  const [showAdmin, setShowAdmin] = useState(false);
  const [managementMode, setManagementMode] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [showPasswordPrompt, setShowPasswordPrompt] = useState<{ type: 'add' | 'manage' } | null>(null);
  const [passwordInput, setPasswordInput] = useState('');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  const categories: Record<Gender, CatalogCategory[]> = {
    'Feminino': ['Vestido de Noiva', 'Vestido de Festa'],
    'Masculino': ['Traje do Noivo', 'Terno Social']
  };

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const genderMatch = item.gender === selectedGender;
      const categoryMatch = selectedCategory === 'Todas' || item.category === selectedCategory;
      const visibilityMatch = managementMode ? true : item.isVisible;
      return genderMatch && categoryMatch && visibilityMatch;
    });
  }, [items, selectedGender, selectedCategory, managementMode]);

  const handleAdminAction = (type: 'add' | 'manage') => {
    if (isAdminAuthenticated) {
      if (type === 'add') setShowAdmin(true);
      if (type === 'manage') {
        if (managementMode) {
          setManagementMode(false);
          setIsAdminAuthenticated(false); // Reset auth when exiting management for security
        } else {
          setManagementMode(true);
        }
      }
    } else {
      setShowPasswordPrompt({ type });
    }
  };

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === '2312') {
      setIsAdminAuthenticated(true);
      const type = showPasswordPrompt?.type;
      setShowPasswordPrompt(null);
      setPasswordInput('');
      if (type === 'add') setShowAdmin(true);
      if (type === 'manage') setManagementMode(true);
    } else {
      alert("Senha de gerenciamento incorreta.");
      setPasswordInput('');
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-6 lg:px-12 animate-fade-in relative">
      {/* Lightbox para visualização ampliada */}
      {selectedImage && (
        <div 
          className="fixed inset-0 z-[200] bg-stone-900/95 flex items-center justify-center p-4 md:p-12 animate-fade-in cursor-zoom-out"
          onClick={() => setSelectedImage(null)}
        >
          <button className="absolute top-6 right-6 text-white hover:text-brand-gold transition-colors">
            <X size={40} />
          </button>
          <img 
            src={selectedImage} 
            alt="Detalhe do Modelo" 
            className="max-w-full max-h-full object-contain shadow-2xl rounded-sm border border-white/10"
          />
        </div>
      )}

      {/* Prompt de Senha para Gestão */}
      {showPasswordPrompt && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center p-4 bg-stone-900/60 backdrop-blur-sm">
          <div className="bg-white p-8 rounded-sm shadow-2xl w-full max-w-sm border-t-4 border-brand-gold animate-fade-in">
            <div className="flex justify-between items-center mb-6">
              <div className="flex items-center space-x-3">
                <Lock size={20} className="text-brand-gold" />
                <h3 className="font-serif text-xl text-stone-900">Acesso Restrito</h3>
              </div>
              <button onClick={() => setShowPasswordPrompt(null)} className="text-stone-300 hover:text-stone-600">
                <X size={20}/>
              </button>
            </div>
            <p className="text-[10px] uppercase tracking-widest text-stone-400 mb-6 font-bold">Senha de Gerenciamento Requerida</p>
            <form onSubmit={handlePasswordSubmit} className="space-y-4">
              <input 
                type="password" 
                autoFocus
                value={passwordInput}
                onChange={(e) => setPasswordInput(e.target.value)}
                placeholder="Insira a senha de acesso"
                className="w-full p-4 bg-stone-50 border border-stone-100 focus:border-brand-gold outline-none text-center text-lg tracking-[0.5em] font-bold"
              />
              <button className="w-full py-4 bg-stone-900 text-white text-[10px] uppercase tracking-widest font-bold hover:bg-brand-gold transition-all shadow-lg">
                Confirmar Senha
              </button>
            </form>
          </div>
        </div>
      )}

      {showAdmin && (
        <AdminPanel 
          onClose={() => setShowAdmin(false)} 
          onAddItem={onAddItem} 
        />
      )}

      {/* BARRA DE FERRAMENTAS DO CATÁLOGO - ADICIONAR E GERENCIAR LADO A LADO */}
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-16 space-y-6 md:space-y-0">
        {onBack && (
          <button 
            onClick={onBack}
            className="group flex items-center space-x-3 text-stone-400 hover:text-brand-gold transition-colors"
          >
            <ArrowLeft size={18} className="group-hover:-translate-x-1 transition-transform" />
            <span className="text-[10px] uppercase tracking-[0.3em] font-bold">Voltar ao Início</span>
          </button>
        )}

        <div className="flex items-center bg-brand-offwhite p-1 rounded-sm border border-stone-100 shadow-sm">
          <button 
            onClick={() => handleAdminAction('add')}
            className="flex items-center space-x-3 px-6 py-3 bg-white border border-stone-100 text-stone-700 hover:text-brand-gold hover:border-brand-gold transition-all rounded-sm text-[10px] uppercase tracking-[0.2em] font-bold"
          >
            <PlusCircle size={16} />
            <span>Adicionar Modelo</span>
          </button>

          <div className="w-[1px] h-6 bg-stone-200 mx-1"></div>

          <button 
            onClick={() => handleAdminAction('manage')}
            className={`flex items-center space-x-3 px-6 py-3 transition-all rounded-sm text-[10px] uppercase tracking-[0.2em] font-bold ${
              managementMode 
              ? 'bg-stone-900 text-white shadow-md' 
              : 'bg-white text-stone-700 hover:text-brand-gold'
            }`}
          >
            <Settings size={16} className={managementMode ? 'animate-spin-slow' : ''} />
            <span>{managementMode ? 'Encerrar Gestão' : 'Gerenciar'}</span>
          </button>
        </div>
      </div>

      <div className="text-center mb-16">
        <h2 className="text-brand-gold text-xs font-bold uppercase tracking-[0.6em] mb-6">Coleções Ellegance</h2>
        <h3 className="text-4xl md:text-6xl font-serif text-stone-900 mb-8 leading-tight">
          Nossa <span className="italic text-brand-rose">Vitrine Digital.</span>
        </h3>
        <p className="max-w-2xl mx-auto text-stone-500 text-lg font-light leading-relaxed">
          {managementMode 
            ? 'Modo de Gestão Ativo: Clique no ícone de lápis em cada modelo para gerenciar visibilidade e disponibilidade.' 
