            <p className="text-stone-500 text-sm mb-8 max-w-sm">Tente alterar a categoria ou a cor selecionada para ver mais opções do nosso acervo.</p>
            <button 
              onClick={() => { setSelectedCategory('Todas'); setSelectedColor('Todas'); }}
              className="px-12 py-5 bg-stone-900 text-white text-[11px] uppercase tracking-widest font-bold hover:bg-brand-gold transition-all shadow-xl"
            >
              Limpar Filtros
            </button>
          </div>
        )}
      </div>
      <style dangerouslySetInnerHTML={{ __html: `@keyframes spin-slow { from { transform: rotate(0deg); } to { transform: rotate(360deg); } } .animate-spin-slow { animation: spin-slow 8s linear infinite; }` }} />
    </div>
  );
};

