import React, { useState, useRef } from 'react';
import { X, Upload, Plus, Check, Database, Copy, Save } from 'lucide-react';
import { CatalogItem, Gender, CatalogCategory } from './Gallery';

interface AdminPanelProps {
  onAddItem: (item: Omit<CatalogItem, 'id'>) => void;
  onClose: () => void;
  currentItems: CatalogItem[];
  onImport: (items: CatalogItem[]) => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ onAddItem, onClose, currentItems, onImport }) => {
  const [name, setName] = useState('');
  const [color, setColor] = useState('');
  const [gender, setGender] = useState<Gender>('Feminino');
  const [category, setCategory] = useState<CatalogCategory>('Vestido de Festa');
  const [image, setImage] = useState<string | null>(null);
  const [isSuccess, setIsSuccess] = useState(false);
  const [showBackup, setShowBackup] = useState(false);
  const [importText, setImportText] = useState('');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 1.5 * 1024 * 1024) {
        alert("Esta imagem é muito pesada (maior que 1.5MB). Para garantir que ela fique salva no navegador, use uma foto mais leve.");
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !color || !image) return;
    onAddItem({ name, color, gender, category, image, isVisible: true, isAvailable: true });
    setIsSuccess(true);
    setTimeout(() => onClose(), 1500);
  };

  const handleCopyBackup = () => {
    const data = JSON.stringify(currentItems);
    navigator.clipboard.writeText(data);
    alert("Código do Catálogo copiado! Guarde este texto em um lugar seguro. Se precisar restaurar seu site, é só colar esse código aqui.");
  };

  const handleImport = () => {
    try {
      const data = JSON.parse(importText);
      if (Array.isArray(data)) {
        onImport(data);
        alert("Catálogo restaurado com sucesso!");
        onClose();
      }
    } catch (e) {
      alert("Código inválido. Certifique-se de colar o código exatamente como copiado.");
    }
  };

  return (
    <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-stone-900/60 backdrop-blur-sm animate-fade-in">
      <div className="bg-white w-full max-w-2xl rounded-sm shadow-2xl overflow-hidden flex flex-col md:flex-row max-h-[90vh]">
        <div className="w-full md:w-1/2 bg-brand-offwhite border-b md:border-b-0 md:border-r border-stone-100 flex flex-col items-center justify-center p-8">
          {image ? (
            <div className="relative w-full aspect-[3/4] rounded-sm overflow-hidden shadow-lg border-2 border-brand-rose">
              <img src={image} alt="Preview" className="w-full h-full object-cover" />
              <button onClick={() => setImage(null)} className="absolute top-2 right-2 p-2 bg-white/80 rounded-full text-stone-800"><X size={16} /></button>
            </div>
          ) : (
            <button onClick={() => fileInputRef.current?.click()} className="w-full aspect-[3/4] border-2 border-dashed border-stone-200 rounded-sm flex flex-col items-center justify-center space-y-4 hover:border-brand-gold hover:bg-white transition-all group">
              <div className="p-4 bg-white rounded-full text-stone-300 group-hover:text-brand-gold shadow-sm"><Upload size={32} /></div>
              <div className="text-center"><p className="text-[10px] uppercase tracking-widest font-bold text-stone-400">Carregar Foto</p></div>
            </button>
          )}
          <input type="file" ref={fileInputRef} onChange={handleImageChange} accept="image/*" className="hidden" />

          <button onClick={() => setShowBackup(!showBackup)} className="mt-8 text-[9px] uppercase tracking-widest text-stone-400 hover:text-brand-gold flex items-center space-x-2">
            <Database size={12} /><span>{showBackup ? 'Voltar para Cadastro' : 'Gerenciar Backup/Restauração'}</span>
          </button>
        </div>

        <div className="w-full md:w-1/2 p-8 flex flex-col relative overflow-y-auto">
          <button onClick={onClose} className="absolute top-4 right-4 text-stone-300 hover:text-stone-800"><X size={20} /></button>

          {!showBackup ? (
            <form onSubmit={handleSubmit} className="space-y-6">
              <h3 className="font-serif text-2xl text-stone-900 mb-2">Cadastrar Modelo</h3>
              <p className="text-[9px] uppercase tracking-[0.3em] text-brand-gold font-bold mb-8">Plotagem Permanente</p>

              <div>
                <label className="block text-[10px] uppercase tracking-widest font-bold text-stone-400 mb-2">Nome do Modelo</label>
                <input type="text" value={name} onChange={(e) => setName(e.target.value)} placeholder="Ex: Vestido Sereia com Renda" className="w-full p-3 border-b border-stone-100 focus:border-brand-gold outline-none text-sm" required />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] uppercase tracking-widest font-bold text-stone-400 mb-2">Linha</label>
                  <select value={gender} onChange={(e) => setGender(e.target.value as Gender)} className="w-full p-3 border-b border-stone-100 focus:border-brand-gold outline-none text-sm bg-transparent">
                    <option value="Feminino">Feminina</option><option value="Masculino">Masculina</option>
                  </select>
                </div>
                <div>
                  <label className="block text-[10px] uppercase tracking-widest font-bold text-stone-400 mb-2">Tipo</label>
                  <select value={category} onChange={(e) => setCategory(e.target.value as CatalogCategory)} className="w-full p-3 border-b border-stone-100 focus:border-brand-gold outline-none text-sm bg-transparent">
                    {gender === 'Feminino' ? (<><option value="Vestido de Noiva">Vestido de Noiva</option><option value="Vestido de Festa">Vestido de Festa</option></>) : (<><option value="Traje do Noivo">Traje do Noivo</option><option value="Terno Social">Terno Social</option></>)}
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-[10px] uppercase tracking-widest font-bold text-stone-400 mb-2">Cor</label>
                <input type="text" value={color} onChange={(e) => setColor(e.target.value)} placeholder="Ex: Rosé, Off-White" className="w-full p-3 border-b border-stone-100 focus:border-brand-gold outline-none text-sm" required />
              </div>

              <button type="submit" disabled={isSuccess || !image} className={`w-full py-4 flex items-center justify-center space-x-3 text-[10px] uppercase tracking-widest font-bold transition-all ${isSuccess ? 'bg-green-500 text-white' : 'bg-stone-900 text-white hover:bg-brand-gold shadow-lg'}`}>
                {isSuccess ? <><Check size={16} /><span>Adicionado!</span></> : <><Plus size={16} /><span>Salvar no Acervo</span></>}
              </button>
            </form>
          ) : (
            <div className="space-y-6">
              <h3 className="font-serif text-2xl text-stone-900 mb-2">Backup de Segurança</h3>
              <p className="text-[9px] uppercase tracking-[0.3em] text-brand-gold font-bold mb-8">Segurança dos Seus Dados</p>

              <div className="p-4 bg-stone-50 border border-stone-100 rounded-sm">
                <p className="text-[10px] text-stone-500 mb-4">Se você quiser salvar seu catálogo para sempre ou enviar para o suporte técnico:</p>
                <button onClick={handleCopyBackup} className="w-full py-3 bg-white border border-stone-200 text-stone-600 text-[9px] uppercase tracking-widest font-bold flex items-center justify-center space-x-2 hover:border-brand-gold transition-all shadow-sm">
                  <Copy size={14} /><span>Copiar Código do Catálogo</span>
                </button>
              </div>

              <div className="pt-6 border-t border-stone-100">
                <p className="text-[10px] uppercase tracking-widest font-bold text-stone-400 mb-2">Restaurar de um Código</p>
                <textarea value={importText} onChange={(e) => setImportText(e.target.value)} placeholder="Cole aqui o código do catálogo para restaurar..." className="w-full h-32 p-3 bg-stone-50 border border-stone-100 focus:border-brand-gold outline-none text-[8px] font-mono mb-4" />
                <button onClick={handleImport} disabled={!importText} className="w-full py-4 bg-stone-900 text-white text-[10px] uppercase tracking-widest font-bold flex items-center justify-center space-x-2 hover:bg-brand-gold transition-all disabled:opacity-30">
                  <Save size={16} /><span>Restaurar Catálogo</span>
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  MessageCircle, 
  ArrowLeft, 
  User, 
  Users, 
  Sparkles, 
  Settings, 
  Eye, 
  EyeOff, 
  Slash, 
  CheckCircle, 
  X, 
  Maximize2,
  Lock,
  Trash2,
  Pencil,
  Palette,
  Database,
  Plus
} from 'lucide-react';
import AdminPanel from './AdminPanel';

export type Gender = 'Feminino' | 'Masculino';
export type CatalogCategory = 'Vestido de Noiva' | 'Vestido de Festa' | 'Traje do Noivo' | 'Terno Social';

export interface CatalogItem {
  id: number;
  name: string;
  gender: Gender;
  category: CatalogCategory;
  color: string;
  image: string;
  isNew?: boolean;
  isVisible: boolean;
  isAvailable: boolean;
  tag?: string;
}

interface GalleryProps {
  items: CatalogItem[];
  onBack?: () => void;
  onAddItem: (item: Omit<CatalogItem, 'id'>) => void;
  onUpdateItems: (items: CatalogItem[]) => void;
  onToggleVisibility: (id: number) => void;
  onToggleAvailability: (id: number) => void;
  onDeleteItem: (id: number) => void;
}

const Gallery: React.FC<GalleryProps> = ({ 
  items, 
  onBack, 
  onAddItem, 
  onUpdateItems,
  onToggleVisibility, 
  onToggleAvailability,
  onDeleteItem
}) => {
  const [selectedGender, setSelectedGender] = useState<Gender>('Feminino');
  const [selectedCategory, setSelectedCategory] = useState<CatalogCategory | 'Todas'>('Todas');
  const [selectedColor, setSelectedColor] = useState<string | 'Todas'>('Todas');
  const [showAdmin, setShowAdmin] = useState(false);
  const [managementMode, setManagementMode] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [showPasswordPrompt, setShowPasswordPrompt] = useState<{ type: 'add' | 'manage' } | null>(null);
  const [passwordInput, setPasswordInput] = useState('');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  const categories: Record<Gender, CatalogCategory[]> = {
    'Feminino': ['Vestido de Noiva', 'Vestido de Festa'],
    'Masculino': ['Traje do Noivo', 'Terno Social']
  };

  useEffect(() => {
    setSelectedCategory('Todas');
    setSelectedColor('Todas');
  }, [selectedGender]);

  const availableColors = useMemo(() => {
    const colors = new Set<string>();
    items.forEach(item => {
      if (item.gender === selectedGender) {
        if (selectedCategory === 'Todas' || item.category === selectedCategory) {
          colors.add(item.color);
        }
      }
    });
    return Array.from(colors).sort();
  }, [items, selectedGender, selectedCategory]);

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const genderMatch = item.gender === selectedGender;
      const categoryMatch = selectedCategory === 'Todas' || item.category === selectedCategory;
      const colorMatch = selectedColor === 'Todas' || item.color.toLowerCase() === selectedColor.toLowerCase();
      const visibilityMatch = managementMode ? true : item.isVisible;
      return genderMatch && categoryMatch && colorMatch && visibilityMatch;
    });
  }, [items, selectedGender, selectedCategory, selectedColor, managementMode]);

  const handleAdminAction = (type: 'add' | 'manage') => {
    if (isAdminAuthenticated) {
      if (type === 'add') setShowAdmin(true);
      if (type === 'manage') setManagementMode(!managementMode);
    } else {
      setShowPasswordPrompt({ type });
    }
  };

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === '2312') {
      setIsAdminAuthenticated(true);
      const type = showPasswordPrompt?.type;
      setShowPasswordPrompt(null);
      setPasswordInput('');
      if (type === 'add') setShowAdmin(true);
      if (type === 'manage') setManagementMode(true);
    } else {
      alert("Senha incorreta.");
      setPasswordInput('');
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-6 lg:px-12 animate-fade-in relative">
      {selectedImage && (
        <div className="fixed inset-0 z-[200] bg-stone-900/95 flex items-center justify-center p-4 md:p-12 animate-fade-in cursor-zoom-out" onClick={() => setSelectedImage(null)}>
          <button className="absolute top-6 right-6 text-white hover:text-brand-gold"><X size={32} /></button>
          <img src={selectedImage} alt="Preview" className="max-w-full max-h-full object-contain shadow-2xl rounded-sm" />
        </div>
      )}

      {showPasswordPrompt && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center p-4 bg-stone-900/60 backdrop-blur-sm">
          <div className="bg-white p-8 rounded-sm shadow-2xl w-full max-w-sm border-t-4 border-brand-gold animate-fade-in">
            <div className="flex justify-between items-center mb-6">
              <div className="flex items-center space-x-2">
                <Lock size={18} className="text-brand-gold" />
                <h3 className="font-serif text-xl text-stone-900">Acesso Restrito</h3>
              </div>
              <button onClick={() => setShowPasswordPrompt(null)} className="text-stone-300 hover:text-stone-600"><X size={20}/></button>
            </div>
            <form onSubmit={handlePasswordSubmit} className="space-y-4">
              <input type="password" autoFocus value={passwordInput} onChange={(e) => setPasswordInput(e.target.value)} placeholder="Senha (2312)" className="w-full p-4 bg-stone-50 border border-stone-100 focus:border-brand-gold outline-none text-center text-lg tracking-[0.5em] font-bold" />
              <button className="w-full py-4 bg-stone-900 text-white text-[10px] uppercase tracking-widest font-bold hover:bg-brand-gold transition-all">Confirmar</button>
            </form>
          </div>
        </div>
      )}

      {showAdmin && <AdminPanel onClose={() => setShowAdmin(false)} onAddItem={onAddItem} currentItems={items} onImport={onUpdateItems} />}

      <div className="flex flex-col md:flex-row md:items-center justify-between mb-16 space-y-6 md:space-y-0">
        {onBack && (
          <button onClick={onBack} className="group flex items-center space-x-2 text-stone-400 hover:text-brand-gold transition-colors">
            <ArrowLeft size={18} className="group-hover:-translate-x-1 transition-transform" />
            <span className="text-[10px] uppercase tracking-[0.3em] font-bold">Início</span>
          </button>
        )}

        <div className="flex items-center space-x-4">
          <button onClick={() => handleAdminAction('add')} className="flex items-center space-x-3 px-8 py-3 bg-white border border-stone-200 text-stone-600 hover:border-stone-400 transition-all rounded-sm text-[11px] uppercase tracking-widest font-bold">
            <Plus size={16} /><span>ADICIONAR</span>
          </button>
          <button onClick={() => handleAdminAction('manage')} className={`flex items-center space-x-3 px-8 py-3 bg-white border-2 transition-all rounded-md text-[11px] uppercase tracking-widest font-bold ${managementMode ? 'border-brand-gold text-brand-gold shadow-md' : 'border-stone-900 text-stone-900'}`}>
            <Settings size={18} className={managementMode ? 'animate-spin-slow' : ''} /><span>GERENCIAR</span>
          </button>
        </div>
      </div>

      <div className="text-center mb-16">
        <h2 className="text-brand-gold text-xs font-bold uppercase tracking-[0.6em] mb-6">Coleções Ellegance</h2>
        <h3 className="text-4xl md:text-6xl font-serif text-stone-900 mb-8 leading-tight">Nossa <span className="italic text-brand-rose">Vitrine Digital.</span></h3>
        <p className="max-w-2xl mx-auto text-stone-500 text-lg font-light leading-relaxed">
          {managementMode ? 'Atenção: Use fotos leves (abaixo de 1MB) para garantir o salvamento no navegador.' : 'Explore nosso acervo completo. Filtre por linha, categoria ou cor para encontrar o modelo ideal.'}
        </p>
      </div>

      <div className="flex flex-col items-center mb-20 space-y-12">
