          <button onClick={() => setSelectedGender('Feminino')} className={`flex items-center space-x-3 px-10 py-3 rounded-sm text-[10px] uppercase tracking-[0.2em] font-bold transition-all ${selectedGender === 'Feminino' ? 'bg-stone-900 text-white shadow-xl' : 'text-stone-400 hover:text-brand-gold'}`}>
            <Users size={16} /><span>Feminino</span>
          </button>
          <button onClick={() => setSelectedGender('Masculino')} className={`flex items-center space-x-3 px-10 py-3 rounded-sm text-[10px] uppercase tracking-[0.2em] font-bold transition-all ${selectedGender === 'Masculino' ? 'bg-stone-900 text-white shadow-xl' : 'text-stone-400 hover:text-brand-gold'}`}>
            <User size={16} /><span>Masculino</span>
          </button>
        </div>

        {/* Filtro de Categorias */}
        <div className="flex flex-wrap justify-center gap-3">
          <button onClick={() => setSelectedCategory('Todas')} className={`px-6 py-2 text-[9px] uppercase tracking-[0.2em] font-bold rounded-sm border transition-all ${selectedCategory === 'Todas' ? 'bg-stone-900 border-stone-900 text-white shadow-md' : 'bg-white border-stone-100 text-stone-400 hover:border-brand-gold hover:text-brand-gold'}`}>
            Todas Categorias
          </button>
          {dynamicCategories.map(cat => (
            <button key={cat} onClick={() => setSelectedCategory(cat)} className={`px-6 py-2 text-[9px] uppercase tracking-[0.2em] font-bold rounded-sm border transition-all ${selectedCategory === cat ? 'bg-stone-900 border-stone-900 text-white shadow-md' : 'bg-white border-stone-100 text-stone-400 hover:border-brand-gold hover:text-brand-gold'}`}>
              {cat}
            </button>
          ))}
        </div>

        {/* Filtros de Cor e Tamanho (Condicionais) */}
        <div className="w-full max-w-4xl grid grid-cols-1 md:grid-cols-2 gap-8 border-t border-stone-100 pt-10">
          {/* Cor */}
          <div className="flex flex-col items-center md:items-start space-y-4">
            <div className="flex items-center space-x-2 text-stone-400">
              <Palette size={14} className="text-brand-gold" />
              <span className="text-[9px] uppercase tracking-[0.3em] font-bold">Cores</span>
            </div>
            <div className="flex flex-wrap justify-center md:justify-start gap-2">
              <button onClick={() => setSelectedColor('Todas')} className={`px-4 py-1.5 text-[8px] uppercase tracking-[0.15em] font-bold rounded-full border transition-all ${selectedColor === 'Todas' ? 'bg-brand-gold border-brand-gold text-white shadow-sm' : 'bg-white border-stone-100 text-stone-400 hover:border-brand-gold'}`}>
                Todas
              </button>
              {availableColors.map(color => (
                <button key={color} onClick={() => setSelectedColor(color)} className={`px-4 py-1.5 text-[8px] uppercase tracking-[0.15em] font-bold rounded-full border transition-all ${selectedColor === color ? 'bg-brand-gold border-brand-gold text-white shadow-sm' : 'bg-white border-stone-100 text-stone-400 hover:border-brand-gold'}`}>
                  {color}
                </button>
              ))}
            </div>
          </div>

          {/* Tamanho */}
          <div className="flex flex-col items-center md:items-start space-y-4">
            <div className="flex items-center space-x-2 text-stone-400">
              <Maximize size={14} className="text-brand-gold" />
              <span className="text-[9px] uppercase tracking-[0.3em] font-bold">Tamanhos</span>
            </div>
            <div className="flex flex-wrap justify-center md:justify-start gap-2">
              <button onClick={() => setSelectedSize('Todos')} className={`px-4 py-1.5 text-[8px] uppercase tracking-[0.15em] font-bold rounded-full border transition-all ${selectedSize === 'Todos' ? 'bg-brand-gold border-brand-gold text-white shadow-sm' : 'bg-white border-stone-100 text-stone-400 hover:border-brand-gold'}`}>
                Todos
              </button>
              {availableSizes.map(size => (
                <button key={size} onClick={() => setSelectedSize(size)} className={`px-4 py-1.5 text-[8px] uppercase tracking-[0.15em] font-bold rounded-full border transition-all ${selectedSize === size ? 'bg-brand-gold border-brand-gold text-white shadow-sm' : 'bg-white border-stone-100 text-stone-400 hover:border-brand-gold'}`}>
                  {size}
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>

      <div className="flex justify-center min-h-[400px] mb-20">
        {filteredItems.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-x-12 gap-y-20 w-full">
            {filteredItems.map((item) => (
